VALUES
  ('aboriginal-f0899a01-moex-00157', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', 'A公司設廠依法應實施環境影響評估，經主管機關進行環境影響評估後，作成不應開發之審查結論。 A不服依法提起訴願，經遭駁回後，應提起下列何種訴訟類型請求救濟，最為適當？', '["再訴願", "確認訴訟", "一般給付訴訟", "課予義務訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00158', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '外國人甲在我國旅遊時，自行到水流湍急之溪邊戲水，後遭山洪衝走溺斃，經調查事實後，當時該水 域並未設立任何禁止戲水之告示。然而，甲之非我國籍配偶仍不得主張國家賠償，依國家賠償法規定， 其最可能為下列何種原因？', '["自然水域不適用國家賠償法", "因不具有因果關係", "基於平等互惠原則", "因甲之配偶不是當事人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00159', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬國家賠償法所稱之公務員？', '["內政部部長", "公立學校教師", "受主管機關委託為機車排放空氣污染物檢驗之檢驗人員", "路口指揮交通之熱心民眾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00160', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '國家對於正當使用合法藥物而受害者，給予藥害救濟，其性質為下列何者？', '["國家賠償", "行政補償", "公法上不當得利", "民事損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00161', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲市政府與乙公司簽訂公共停車場之BOT契約，乙公司設置機械式停車場經營，某次因機械故障造 成丙之車輛嚴重受損。經調查後，甲市政府並未違反其行政監督責任，丙得依下列何種方式求償？', '["向甲請求國家賠償", "得向甲及乙請求民事連帶損害賠償", "向乙請求民事賠償", "向甲之承辦人請求民事賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00162', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於我國現行國家賠償責任之敘述，下列何者錯誤？', '["國家賠償法制定後現行法制中業已不存在特別國家賠償責任", "國家賠償法主要類型為公務員國家賠償責任及公共設施之國家賠償責任", "在我國憲法本文中就國家賠償制度有相關規定", "人民依國家賠償法提起國家賠償訴訟前，必須先踐行協議程序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00163', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-9a3b44c4', 'sub-aboriginal-f0899a01-04', NULL, 'essay', '甲因涉嫌傷害罪遭到偵辦。甲於警方詢問時，坦承確實有打傷被害人乙。
後於檢察官訊問時，回答「是我做的沒錯，我在警察局都講過了。」檢
察官將甲依傷害罪提起公訴。審判時，甲行使緘默權，拒絕回答任何問
題。法官審理後，認為甲於偵查階段向警方及檢察官之二次承認傷害均
係在自由意志下陳述，內容甚為可信，依此判決甲傷害罪。試問法院之
判決是否適法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "4bd43b941d9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00164', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-9a3b44c4', 'sub-aboriginal-f0899a01-04', NULL, 'essay', '甲提告乙某日將其打傷，檢察官偵查後，認為乙之犯罪嫌疑不足，對乙
做出不起訴處分。甲不服，依法聲請再議，又遭駁回。試問甲是否還有
救濟之途？請說明。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "4bd43b941d9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00165', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-9a3b44c4', 'sub-aboriginal-f0899a01-04', NULL, 'essay', '甲不幸遭乙強制猥褻後，立刻將乙的惡行過程記載於日記。後乙遭起訴，
檢察官提出甲書寫的前述日記內容做為證據，乙則主張此一書寫之紙本
內容無證據能力。試問乙之主張有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "4bd43b941d9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00166', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-9a3b44c4', 'sub-aboriginal-f0899a01-04', NULL, 'essay', '甲涉嫌於某日進入某超商竊取新臺幣（下同）3,000 元，檢察官綜合相關
證據等，起訴甲竊盜罪。審判時，法官勘驗當時超商之監視攝影器畫面，
發現甲有拿出利刃抵住店員後強取 3,000 元，遂告知甲所涉嫌罪名為強
盜罪，甲及其辯護律師均表示沒意見。後法院判決甲成立強盜罪。試問
此判決是否適法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "4bd43b941d9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
